// Builds a browser-ready IIFE bundle of @peptiderx/atl-verifier that
// exposes the public PDA surface on window.AtlVerifier. Consumed by the
// "Verify a PDA" panel on web/atlas.html.
//
// Output: web/vendor/atl-verifier.iife.js (committed; no build step
// required to open atlas.html via file://).
//
// Why IIFE: the target is a static HTML page that must work when
// opened directly from disk (file://). Native ES modules load under
// file:// in Chromium + Firefox, but Safari and older browsers choke
// on module resolution from file://. An IIFE with a global attached
// to `window` is the lowest-common-denominator format and matches the
// atl-001 fallback pattern already in atlas.html.
//
// Bundle size target: under 80 KB minified. The verifier is pure
// WebCrypto and has no runtime deps, so the only payload is the
// canonical-JSON encoder, the hashing helpers, and the PDA verifier
// itself.

import { build } from "esbuild";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { statSync, writeFileSync } from "node:fs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const pkgRoot = resolve(__dirname, "..");
const repoRoot = resolve(pkgRoot, "..", "..", "..");
const entry = join(pkgRoot, "src", "index.ts");
const outFile = join(repoRoot, "web", "vendor", "atl-verifier.iife.js");

const banner = `/*!
 * @peptiderx/atl-verifier · browser IIFE bundle
 * Generated by sdk/packages/atl-verifier/scripts/build-atlas-bundle.mjs
 * Rebuild with: pnpm --filter @peptiderx/atl-verifier run build:atlas-bundle
 *
 * Exposes: window.AtlVerifier = { verifyPDA, recomputePdaHex, ... }
 * Research use only, nonclinical.
 */`;

await build({
  entryPoints: [entry],
  bundle: true,
  format: "iife",
  globalName: "AtlVerifier",
  platform: "browser",
  target: ["es2020"],
  minify: true,
  sourcemap: false,
  legalComments: "none",
  banner: { js: banner },
  logLevel: "info",
  outfile: outFile,
  // Ensure the bundle works under file:// with the WebCrypto polyfill
  // that all evergreen browsers ship. No external deps.
  external: [],
});

const size = statSync(outFile).size;
// eslint-disable-next-line no-console
console.log(
  `[atl-verifier] wrote ${outFile} (${size} bytes = ${(size / 1024).toFixed(1)} KB)`,
);

// Emit a small checksum sidecar so we can detect bundle drift in CI.
const { createHash } = await import("node:crypto");
const { readFileSync } = await import("node:fs");
const bytes = readFileSync(outFile);
const sha = createHash("sha256").update(bytes).digest("hex");
writeFileSync(outFile + ".sha256", sha + "  atl-verifier.iife.js\n", "utf8");
// eslint-disable-next-line no-console
console.log(`[atl-verifier] sha256 ${sha}`);
